// A buffer provides the content for a wl_surface. Buffers are
// created through factory interfaces such as wl_shm, wp_linux_buffer_params
// (from the linux-dmabuf protocol extension) or similar. It has a width and
// a height and can be attached to a wl_surface, but the mechanism by which a
// client provides and updates the contents is defined by the buffer factory
// interface.
//
// Color channels are assumed to be electrical rather than optical (in other
// words, encoded with a transfer function) unless otherwise specified. If
// the buffer uses a format that has an alpha channel, the alpha channel is
// assumed to be premultiplied into the electrical color channel values
// (after transfer function encoding) unless otherwise specified.
//
// Note, because wl_buffer objects are created from multiple independent
// factory interfaces, the wl_buffer interface is frozen at version 1.
type WlBuffer struct {
	_   raw.Marker[WlBuffer]
	raw *raw.Object
}

// Conn returns the underlying connection.
func (o WlBuffer) Conn() *wlcl.Connection { return (*wlcl.Connection)(o.raw.Conn()) }

// IsSet returns true if the object is valid (non-zero).
func (o WlBuffer) IsSet() bool { return o.raw != nil }

// Version returns the object's version.
func (o WlBuffer) Version() uint32 { return o.raw.Version() }

// UserData returns the object's user data.
func (o WlBuffer) UserData() WlBufferData { return o.raw.UserData().(WlBufferData) }

// SetUserData sets the object's user data.
func (o WlBuffer) SetUserData(v WlBufferData) { o.raw.SetUserData(v) }

// Destroy a buffer. If and how you need to release the backing
// storage is defined by the buffer factory interface.
//
// For possible side-effects to a surface, see wl_surface.attach.
func (o WlBuffer) Destroy() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 0, func() (args []byte, fds []int) {
		o.raw.Destroy()
		return
	})
	return
}

type WlBufferData interface {
	// Sent when this wl_buffer is no longer used by the compositor.
	//
	// For more information on when release events may or may not be sent,
	// and what consequences it has, please see the description of
	// wl_surface.attach.
	//
	// If a client receives a release event before the frame callback
	// requested in the same wl_surface.commit that attaches this
	// wl_buffer to a surface, then the client is immediately free to
	// reuse the buffer and its backing storage, and does not need a
	// second buffer for the next surface content update. Typically
	// this is possible, when the compositor maintains a copy of the
	// wl_surface contents, e.g. as a GL texture. This is an important
	// optimization for GL(ES) compositors with wl_shm clients.
	HandleWlBufferRelease(ctx context.Context)
}

type WlBufferStub struct{}

func (WlBufferStub) HandleWlBufferRelease(ctx context.Context) {}

func unmarshalEventWlBuffer(o *raw.Object, op uint16, args []byte, fds []int) (raw.HandleEventFunc, error) {
	switch op {
	case 0:
		var (
			err error
		)

		conn := o.Conn()
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlBufferData).HandleWlBufferRelease(ctx)
			} else {
			}
		}, nil
	default:
		return nil, fmt.Errorf("wl_buffer: invalid event opcode %d", op)
	}
}

const WlBufferName = "wl_buffer"

var interfaceWlBuffer = raw.Interface{
	Name:           "wl_buffer",
	Requests:       []string{"destroy"},
	Events:         []string{"release"},
	EventsFDs:      []int{0},
	UnmarshalEvent: unmarshalEventWlBuffer,
}

// A wl_data_offer represents a piece of data offered for transfer
// by another client (the source client).  It is used by the
// copy-and-paste and drag-and-drop mechanisms.  The offer
// describes the different mime types that the data can be
// converted to and provides the mechanism for transferring the
// data directly from the source client.
type WlDataOffer struct {
	_   raw.Marker[WlDataOffer]
	raw *raw.Object
}

// Conn returns the underlying connection.
func (o WlDataOffer) Conn() *wlcl.Connection { return (*wlcl.Connection)(o.raw.Conn()) }

// IsSet returns true if the object is valid (non-zero).
func (o WlDataOffer) IsSet() bool { return o.raw != nil }

// Version returns the object's version.
func (o WlDataOffer) Version() uint32 { return o.raw.Version() }

// UserData returns the object's user data.
func (o WlDataOffer) UserData() WlDataOfferData { return o.raw.UserData().(WlDataOfferData) }

// SetUserData sets the object's user data.
func (o WlDataOffer) SetUserData(v WlDataOfferData) { o.raw.SetUserData(v) }

// Indicate that the client can accept the given mime type, or
// NULL for not accepted.
//
// For objects of version 2 or older, this request is used by the
// client to give feedback whether the client can receive the given
// mime type, or NULL if none is accepted; the feedback does not
// determine whether the drag-and-drop operation succeeds or not.
//
// For objects of version 3 or newer, this request determines the
// final result of the drag-and-drop operation. If the end result
// is that no mime types were accepted, the drag-and-drop operation
// will be cancelled and the corresponding drag source will receive
// wl_data_source.cancelled. Clients may still use this event in
// conjunction with wl_data_source.action for feedback.
func (o WlDataOffer) Accept(serial uint32, mimeType wlcl.NullString) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 0, func() (args []byte, fds []int) {
		args = make([]byte, 0, paddedSize(raw.NullString(mimeType).Size())+8)
		args = conn.MarshalUint(args, serial)
		args = conn.MarshalNullString(args, raw.NullString(mimeType))
		return
	})
	return
}

// To transfer the offered data, the client issues this request
// and indicates the mime type it wants to receive.  The transfer
// happens through the passed file descriptor (typically created
// with the pipe system call).  The source client writes the data
// in the mime type representation requested and then closes the
// file descriptor.
//
// The receiving client reads from the read end of the pipe until
// EOF and then closes its end, at which point the transfer is
// complete.
//
// This request may happen multiple times for different mime types,
// both before and after wl_data_device.drop. Drag-and-drop destination
// clients may preemptively fetch data or examine it more closely to
// determine acceptance.
func (o WlDataOffer) Receive(mimeType string, fd int) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 1, func() (args []byte, fds []int) {
		args = make([]byte, 0, paddedSize(len(mimeType)+1)+4)
		fds = make([]int, 0, 1)
		args = conn.MarshalString(args, mimeType)
		fds = conn.MarshalFD(fds, fd)
		return
	})
	return
}

// Destroy the data offer.
func (o WlDataOffer) Destroy() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 2, func() (args []byte, fds []int) {
		o.raw.Destroy()
		return
	})
	return
}

// Notifies the compositor that the drag destination successfully
// finished the drag-and-drop operation.
//
// Upon receiving this request, the compositor will emit
// wl_data_source.dnd_finished on the drag source client.
//
// It is a client error to perform other requests than
// wl_data_offer.destroy after this one. It is also an error to perform
// this request after a NULL mime type has been set in
// wl_data_offer.accept or no action was received through
// wl_data_offer.action.
//
// If wl_data_offer.finish request is received for a non drag and drop
// operation, the invalid_finish protocol error is raised.
func (o WlDataOffer) Finish() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 3, func() (args []byte, fds []int) {
		return
	})
	return
}

// Sets the actions that the destination side client supports for
// this operation. This request may trigger the emission of
// wl_data_source.action and wl_data_offer.action events if the compositor
// needs to change the selected action.
//
// This request can be called multiple times throughout the
// drag-and-drop operation, typically in response to wl_data_device.enter
// or wl_data_device.motion events.
//
// This request determines the final result of the drag-and-drop
// operation. If the end result is that no action is accepted,
// the drag source will receive wl_data_source.cancelled.
//
// The dnd_actions argument must contain only values expressed in the
// wl_data_device_manager.dnd_actions enum, and the preferred_action
// argument must only contain one of those values set, otherwise it
// will result in a protocol error.
//
// While managing an "ask" action, the destination drag-and-drop client
// may perform further wl_data_offer.receive requests, and is expected
// to perform one last wl_data_offer.set_actions request with a preferred
// action other than "ask" (and optionally wl_data_offer.accept) before
// requesting wl_data_offer.finish, in order to convey the action selected
// by the user. If the preferred action is not in the
// wl_data_offer.source_actions mask, an error will be raised.
//
// If the "ask" action is dismissed (e.g. user cancellation), the client
// is expected to perform wl_data_offer.destroy right away.
//
// This request can only be made on drag-and-drop offers, a protocol error
// will be raised otherwise.
func (o WlDataOffer) SetActions(dndActions uint32, preferredAction uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 4, func() (args []byte, fds []int) {
		args = make([]byte, 0, 8)
		args = conn.MarshalUint(args, dndActions)
		args = conn.MarshalUint(args, preferredAction)
		return
	})
	return
}

type WlDataOfferData interface {
	// Sent immediately after creating the wl_data_offer object.  One
	// event per offered mime type.
	HandleWlDataOfferOffer(ctx context.Context, mimeType string)

	// This event indicates the actions offered by the data source. It
	// will be sent immediately after creating the wl_data_offer object,
	// or anytime the source side changes its offered actions through
	// wl_data_source.set_actions.
	HandleWlDataOfferSourceActions(ctx context.Context, sourceActions uint32)

	// This event indicates the action selected by the compositor after
	// matching the source/destination side actions. Only one action (or
	// none) will be offered here.
	//
	// This event can be emitted multiple times during the drag-and-drop
	// operation in response to destination side action changes through
	// wl_data_offer.set_actions.
	//
	// This event will no longer be emitted after wl_data_device.drop
	// happened on the drag-and-drop destination, the client must
	// honor the last action received, or the last preferred one set
	// through wl_data_offer.set_actions when handling an "ask" action.
	//
	// Compositors may also change the selected action on the fly, mainly
	// in response to keyboard modifier changes during the drag-and-drop
	// operation.
	//
	// The most recent action received is always the valid one. Prior to
	// receiving wl_data_device.drop, the chosen action may change (e.g.
	// due to keyboard modifiers being pressed). At the time of receiving
	// wl_data_device.drop the drag-and-drop destination must honor the
	// last action received.
	//
	// Action changes may still happen after wl_data_device.drop,
	// especially on "ask" actions, where the drag-and-drop destination
	// may choose another action afterwards. Action changes happening
	// at this stage are always the result of inter-client negotiation, the
	// compositor shall no longer be able to induce a different action.
	//
	// Upon "ask" actions, it is expected that the drag-and-drop destination
	// may potentially choose a different action and/or mime type,
	// based on wl_data_offer.source_actions and finally chosen by the
	// user (e.g. popping up a menu with the available options). The
	// final wl_data_offer.set_actions and wl_data_offer.accept requests
	// must happen before the call to wl_data_offer.finish.
	HandleWlDataOfferAction(ctx context.Context, dndAction uint32)
}

type WlDataOfferStub struct{}

func (WlDataOfferStub) HandleWlDataOfferOffer(ctx context.Context, mimeType string) {}

func (WlDataOfferStub) HandleWlDataOfferSourceActions(ctx context.Context, sourceActions uint32) {}

func (WlDataOfferStub) HandleWlDataOfferAction(ctx context.Context, dndAction uint32) {}

func unmarshalEventWlDataOffer(o *raw.Object, op uint16, args []byte, fds []int) (raw.HandleEventFunc, error) {
	switch op {
	case 0:
		var (
			mimeType string
			err      error
		)

		conn := o.Conn()
		if mimeType, args, err = conn.UnmarshalString(args); err != nil {
			return nil, err
		}
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlDataOfferData).HandleWlDataOfferOffer(ctx,
					mimeType,
				)
			} else {
			}
		}, nil
	case 1:
		var (
			sourceActions uint32
			err           error
		)

		conn := o.Conn()
		if sourceActions, args, err = conn.UnmarshalUint(args); err != nil {
			return nil, err
		}
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlDataOfferData).HandleWlDataOfferSourceActions(ctx,
					sourceActions,
				)
			} else {
			}
		}, nil
	case 2:
		var (
			dndAction uint32
			err       error
		)

		conn := o.Conn()
		if dndAction, args, err = conn.UnmarshalUint(args); err != nil {
			return nil, err
		}
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlDataOfferData).HandleWlDataOfferAction(ctx,
					dndAction,
				)
			} else {
			}
		}, nil
	default:
		return nil, fmt.Errorf("wl_data_offer: invalid event opcode %d", op)
	}
}

