// The wl_data_source object is the source side of a wl_data_offer.
// It is created by the source client in a data transfer and
// provides a way to describe the offered data and a way to respond
// to requests to transfer the data.
type WlDataSource struct {
	_   raw.Marker[WlDataSource]
	raw *raw.Object
}

// Conn returns the underlying connection.
func (o WlDataSource) Conn() *wlcl.Connection { return (*wlcl.Connection)(o.raw.Conn()) }

// IsSet returns true if the object is valid (non-zero).
func (o WlDataSource) IsSet() bool { return o.raw != nil }

// Version returns the object's version.
func (o WlDataSource) Version() uint32 { return o.raw.Version() }

// UserData returns the object's user data.
func (o WlDataSource) UserData() WlDataSourceData { return o.raw.UserData().(WlDataSourceData) }

// SetUserData sets the object's user data.
func (o WlDataSource) SetUserData(v WlDataSourceData) { o.raw.SetUserData(v) }

// This request adds a mime type to the set of mime types
// advertised to targets.  Can be called several times to offer
// multiple types.
func (o WlDataSource) Offer(mimeType string) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 0, func() (args []byte, fds []int) {
		args = make([]byte, 0, paddedSize(len(mimeType)+1)+4)
		args = conn.MarshalString(args, mimeType)
		return
	})
	return
}

// Destroy the data source.
func (o WlDataSource) Destroy() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 1, func() (args []byte, fds []int) {
		o.raw.Destroy()
		return
	})
	return
}

// Sets the actions that the source side client supports for this
// operation. This request may trigger wl_data_source.action and
// wl_data_offer.action events if the compositor needs to change the
// selected action.
//
// The dnd_actions argument must contain only values expressed in the
// wl_data_device_manager.dnd_actions enum, otherwise it will result
// in a protocol error.
//
// This request must be made once only, and can only be made on sources
// used in drag-and-drop, so it must be performed before
// wl_data_device.start_drag. Attempting to use the source other than
// for drag-and-drop will raise a protocol error.
func (o WlDataSource) SetActions(dndActions uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 2, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalUint(args, dndActions)
		return
	})
	return
}

type WlDataSourceData interface {
	// Sent when a target accepts pointer_focus or motion events.  If
	// a target does not accept any of the offered types, type is NULL.
	//
	// Used for feedback during drag-and-drop.
	HandleWlDataSourceTarget(ctx context.Context, mimeType wlcl.NullString)

	// Request for data from the client.  Send the data as the
	// specified mime type over the passed file descriptor, then
	// close it.
	HandleWlDataSourceSend(ctx context.Context, mimeType string, fd int)

	// This data source is no longer valid. There are several reasons why
	// this could happen:
	//
	//   - The data source has been replaced by another data source.
	//   - The drag-and-drop operation was performed, but the drop destination
	//     did not accept any of the mime types offered through
	//     wl_data_source.target.
	//   - The drag-and-drop operation was performed, but the drop destination
	//     did not select any of the actions present in the mask offered through
	//     wl_data_source.action.
	//   - The drag-and-drop operation was performed but didn't happen over a
	//     surface.
	//   - The compositor cancelled the drag-and-drop operation (e.g. compositor
	//     dependent timeouts to avoid stale drag-and-drop transfers).
	//
	// The client should clean up and destroy this data source.
	//
	// For objects of version 2 or older, wl_data_source.cancelled will
	// only be emitted if the data source was replaced by another data
	// source.
	HandleWlDataSourceCancelled(ctx context.Context)

	// The user performed the drop action. This event does not indicate
	// acceptance, wl_data_source.cancelled may still be emitted afterwards
	// if the drop destination does not accept any mime type.
	//
	// However, this event might however not be received if the compositor
	// cancelled the drag-and-drop operation before this event could happen.
	//
	// Note that the data_source may still be used in the future and should
	// not be destroyed here.
	HandleWlDataSourceDndDropPerformed(ctx context.Context)

	// The drop destination finished interoperating with this data
	// source, so the client is now free to destroy this data source and
	// free all associated data.
	//
	// If the action used to perform the operation was "move", the
	// source can now delete the transferred data.
	HandleWlDataSourceDndFinished(ctx context.Context)

	// This event indicates the action selected by the compositor after
	// matching the source/destination side actions. Only one action (or
	// none) will be offered here.
	//
	// This event can be emitted multiple times during the drag-and-drop
	// operation, mainly in response to destination side changes through
	// wl_data_offer.set_actions, and as the data device enters/leaves
	// surfaces.
	//
	// It is only possible to receive this event after
	// wl_data_source.dnd_drop_performed if the drag-and-drop operation
	// ended in an "ask" action, in which case the final wl_data_source.action
	// event will happen immediately before wl_data_source.dnd_finished.
	//
	// Compositors may also change the selected action on the fly, mainly
	// in response to keyboard modifier changes during the drag-and-drop
	// operation.
	//
	// The most recent action received is always the valid one. The chosen
	// action may change alongside negotiation (e.g. an "ask" action can turn
	// into a "move" operation), so the effects of the final action must
	// always be applied in wl_data_offer.dnd_finished.
	//
	// Clients can trigger cursor surface changes from this point, so
	// they reflect the current action.
	HandleWlDataSourceAction(ctx context.Context, dndAction uint32)
}

