func (o WlDataDevice) SetUserData(v WlDataDeviceData) { o.raw.SetUserData(v) }

// This request asks the compositor to start a drag-and-drop
// operation on behalf of the client.
//
// The source argument is the data source that provides the data
// for the eventual data transfer. If source is NULL, enter, leave
// and motion events are sent only to the client that initiated the
// drag and the client is expected to handle the data passing
// internally. If source is destroyed, the drag-and-drop session will be
// cancelled.
//
// The origin surface is the surface where the drag originates and
// the client must have an active implicit grab that matches the
// serial.
//
// The icon surface is an optional (can be NULL) surface that
// provides an icon to be moved around with the cursor.  Initially,
// the top-left corner of the icon surface is placed at the cursor
// hotspot, but subsequent wl_surface.offset requests can move the
// relative position. Attach requests must be confirmed with
// wl_surface.commit as usual. The icon surface is given the role of
// a drag-and-drop icon. If the icon surface already has another role,
// it raises a protocol error.
//
// The input region is ignored for wl_surfaces with the role of a
// drag-and-drop icon.
//
// The given source may not be used in any further set_selection or
// start_drag requests. Attempting to reuse a previously-used source
// may send a used_source error.
func (o WlDataDevice) StartDrag(source WlDataSource, origin WlSurface, icon WlSurface, serial uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 0, func() (args []byte, fds []int) {
		args = make([]byte, 0, 16)
		args = conn.MarshalNullObject(args, source.raw)
		args = conn.MarshalObject(args, origin.raw)
		args = conn.MarshalNullObject(args, icon.raw)
		args = conn.MarshalUint(args, serial)
		return
	})
	return
}

// This request asks the compositor to set the selection
// to the data from the source on behalf of the client.
//
// To unset the selection, set the source to NULL.
//
// The given source may not be used in any further set_selection or
// start_drag requests. Attempting to reuse a previously-used source
// may send a used_source error.
func (o WlDataDevice) SetSelection(source WlDataSource, serial uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 1, func() (args []byte, fds []int) {
		args = make([]byte, 0, 8)
		args = conn.MarshalNullObject(args, source.raw)
		args = conn.MarshalUint(args, serial)
		return
	})
	return
}

// This request destroys the data device.
func (o WlDataDevice) Release() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 2, func() (args []byte, fds []int) {
		o.raw.Destroy()
		return
	})
	return
}

type WlDataDeviceData interface {
	// The data_offer event introduces a new wl_data_offer object,
	// which will subsequently be used in either the
	// data_device.enter event (for drag-and-drop) or the
	// data_device.selection event (for selections).  Immediately
	// following the data_device.data_offer event, the new data_offer
	// object will send out data_offer.offer events to describe the
	// mime types it offers.
	HandleWlDataDeviceDataOffer(ctx context.Context, id WlDataOffer)

	// This event is sent when an active drag-and-drop pointer enters
	// a surface owned by the client.  The position of the pointer at
	// enter time is provided by the x and y arguments, in surface-local
	// coordinates.
	HandleWlDataDeviceEnter(ctx context.Context, serial uint32, surface WlSurface, x float32, y float32, id WlDataOffer)

	// This event is sent when the drag-and-drop pointer leaves the
	// surface and the session ends.  The client must destroy the
	// wl_data_offer introduced at enter time at this point.
	HandleWlDataDeviceLeave(ctx context.Context)

	// This event is sent when the drag-and-drop pointer moves within
	// the currently focused surface. The new position of the pointer
	// is provided by the x and y arguments, in surface-local
	// coordinates.
	HandleWlDataDeviceMotion(ctx context.Context, time uint32, x float32, y float32)

	// The event is sent when a drag-and-drop operation is ended
	// because the implicit grab is removed.
	//
	// The drag-and-drop destination is expected to honor the last action
	// received through wl_data_offer.action, if the resulting action is
	// "copy" or "move", the destination can still perform
	// wl_data_offer.receive requests, and is expected to end all
	// transfers with a wl_data_offer.finish request.
	//
	// If the resulting action is "ask", the action will not be considered
	// final. The drag-and-drop destination is expected to perform one last
	// wl_data_offer.set_actions request, or wl_data_offer.destroy in order
	// to cancel the operation.
	HandleWlDataDeviceDrop(ctx context.Context)

	// The selection event is sent out to notify the client of a new
	// wl_data_offer for the selection for this device.  The
	// data_device.data_offer and the data_offer.offer events are
	// sent out immediately before this event to introduce the data
	// offer object.  The selection event is sent to a client
	// immediately before receiving keyboard focus and when a new
	// selection is set while the client has keyboard focus.  The
	// data_offer is valid until a new data_offer or NULL is received
	// or until the client loses keyboard focus.  Switching surface with
	// keyboard focus within the same client doesn't mean a new selection
	// will be sent.  The client must destroy the previous selection
	// data_offer, if any, upon receiving this event.
	HandleWlDataDeviceSelection(ctx context.Context, id WlDataOffer)
}

