func (o WlShellSurface) SetUserData(v WlShellSurfaceData) { o.raw.SetUserData(v) }

// A client must respond to a ping event with a pong request or
// the client may be deemed unresponsive.
func (o WlShellSurface) Pong(serial uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 0, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalUint(args, serial)
		return
	})
	return
}

// Start a pointer-driven move of the surface.
//
// This request must be used in response to a button press event.
// The server may ignore move requests depending on the state of
// the surface (e.g. fullscreen or maximized).
func (o WlShellSurface) Move(seat WlSeat, serial uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 1, func() (args []byte, fds []int) {
		args = make([]byte, 0, 8)
		args = conn.MarshalObject(args, seat.raw)
		args = conn.MarshalUint(args, serial)
		return
	})
	return
}

// Start a pointer-driven resizing of the surface.
//
// This request must be used in response to a button press event.
// The server may ignore resize requests depending on the state of
// the surface (e.g. fullscreen or maximized).
func (o WlShellSurface) Resize(seat WlSeat, serial uint32, edges uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 2, func() (args []byte, fds []int) {
		args = make([]byte, 0, 12)
		args = conn.MarshalObject(args, seat.raw)
		args = conn.MarshalUint(args, serial)
		args = conn.MarshalUint(args, edges)
		return
	})
	return
}

// Map the surface as a toplevel surface.
//
// A toplevel surface is not fullscreen, maximized or transient.
func (o WlShellSurface) SetToplevel() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 3, func() (args []byte, fds []int) {
		return
	})
	return
}

// Map the surface relative to an existing surface.
//
// The x and y arguments specify the location of the upper left
// corner of the surface relative to the upper left corner of the
// parent surface, in surface-local coordinates.
//
// The flags argument controls details of the transient behaviour.
func (o WlShellSurface) SetTransient(parent WlSurface, x int32, y int32, flags uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 4, func() (args []byte, fds []int) {
		args = make([]byte, 0, 16)
		args = conn.MarshalObject(args, parent.raw)
		args = conn.MarshalInt(args, x)
		args = conn.MarshalInt(args, y)
		args = conn.MarshalUint(args, flags)
		return
	})
	return
}

// Map the surface as a fullscreen surface.
//
// If an output parameter is given then the surface will be made
// fullscreen on that output. If the client does not specify the
// output then the compositor will apply its policy - usually
// choosing the output on which the surface has the biggest surface
// area.
//
// The client may specify a method to resolve a size conflict
// between the output size and the surface size - this is provided
// through the method parameter.
//
// The framerate parameter is used only when the method is set
// to "driver", to indicate the preferred framerate. A value of 0
// indicates that the client does not care about framerate.  The
// framerate is specified in mHz, that is framerate of 60000 is 60Hz.
//
// A method of "scale" or "driver" implies a scaling operation of
// the surface, either via a direct scaling operation or a change of
// the output mode. This will override any kind of output scaling, so
// that mapping a surface with a buffer size equal to the mode can
// fill the screen independent of buffer_scale.
//
// A method of "fill" means we don't scale up the buffer, however
// any output scale is applied. This means that you may run into
// an edge case where the application maps a buffer with the same
// size of the output mode but buffer_scale 1 (thus making a
// surface larger than the output). In this case it is allowed to
// downscale the results to fit the screen.
//
// The compositor must reply to this request with a configure event
// with the dimensions for the output on which the surface will
// be made fullscreen.
func (o WlShellSurface) SetFullscreen(method uint32, framerate uint32, output WlOutput) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 5, func() (args []byte, fds []int) {
		args = make([]byte, 0, 12)
		args = conn.MarshalUint(args, method)
		args = conn.MarshalUint(args, framerate)
		args = conn.MarshalNullObject(args, output.raw)
		return
	})
	return
}

// Map the surface as a popup.
//
// A popup surface is a transient surface with an added pointer
// grab.
//
// An existing implicit grab will be changed to owner-events mode,
// and the popup grab will continue after the implicit grab ends
// (i.e. releasing the mouse button does not cause the popup to
// be unmapped).
//
// The popup grab continues until the window is destroyed or a
// mouse button is pressed in any other client's window. A click
// in any of the client's surfaces is reported as normal, however,
// clicks in other clients' surfaces will be discarded and trigger
// the callback.
//
// The x and y arguments specify the location of the upper left
// corner of the surface relative to the upper left corner of the
// parent surface, in surface-local coordinates.
func (o WlShellSurface) SetPopup(seat WlSeat, serial uint32, parent WlSurface, x int32, y int32, flags uint32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 6, func() (args []byte, fds []int) {
		args = make([]byte, 0, 24)
		args = conn.MarshalObject(args, seat.raw)
		args = conn.MarshalUint(args, serial)
		args = conn.MarshalObject(args, parent.raw)
		args = conn.MarshalInt(args, x)
		args = conn.MarshalInt(args, y)
		args = conn.MarshalUint(args, flags)
		return
	})
	return
}

// Map the surface as a maximized surface.
//
// If an output parameter is given then the surface will be
// maximized on that output. If the client does not specify the
// output then the compositor will apply its policy - usually
// choosing the output on which the surface has the biggest surface
// area.
//
// The compositor will reply with a configure event telling
// the expected new surface size. The operation is completed
// on the next buffer attach to this surface.
//
// A maximized surface typically fills the entire output it is
// bound to, except for desktop elements such as panels. This is
// the main difference between a maximized shell surface and a
// fullscreen shell surface.
//
// The details depend on the compositor implementation.
func (o WlShellSurface) SetMaximized(output WlOutput) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 7, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalNullObject(args, output.raw)
		return
	})
	return
}

// Set a short title for the surface.
//
// This string may be used to identify the surface in a task bar,
// window list, or other user interface elements provided by the
// compositor.
//
// The string must be encoded in UTF-8.
func (o WlShellSurface) SetTitle(title string) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 8, func() (args []byte, fds []int) {
		args = make([]byte, 0, paddedSize(len(title)+1)+4)
		args = conn.MarshalString(args, title)
		return
	})
	return
}

// Set a class for the surface.
//
// The surface class identifies the general class of applications
// to which the surface belongs. A common convention is to use the
// file name (or the full path if it is a non-standard location) of
// the application's .desktop file as the class.
func (o WlShellSurface) SetClass(class string) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 9, func() (args []byte, fds []int) {
		args = make([]byte, 0, paddedSize(len(class)+1)+4)
		args = conn.MarshalString(args, class)
		return
	})
	return
}

type WlShellSurfaceData interface {
	// Ping a client to check if it is receiving events and sending
	// requests. A client is expected to reply with a pong request.
	HandleWlShellSurfacePing(ctx context.Context, serial uint32)

	// The configure event asks the client to resize its surface.
	//
	// The size is a hint, in the sense that the client is free to
	// ignore it if it doesn't resize, pick a smaller size (to
	// satisfy aspect ratio or resize in steps of NxM pixels).
	//
	// The edges parameter provides a hint about how the surface
	// was resized. The client may use this information to decide
	// how to adjust its content to the new size (e.g. a scrolling
	// area might adjust its content position to leave the viewable
	// content unmoved).
	//
	// The client is free to dismiss all but the last configure
	// event it received.
	//
	// The width and height arguments specify the size of the window
	// in surface-local coordinates.
	HandleWlShellSurfaceConfigure(ctx context.Context, edges uint32, width int32, height int32)

	// The popup_done event is sent out when a popup grab is broken,
	// that is, when the user clicks a surface that doesn't belong
	// to the client owning the popup surface.
	HandleWlShellSurfacePopupDone(ctx context.Context)
}

type WlShellSurfaceStub struct{}

func (WlShellSurfaceStub) HandleWlShellSurfacePing(ctx context.Context, serial uint32) {}

func (WlShellSurfaceStub) HandleWlShellSurfaceConfigure(ctx context.Context, edges uint32, width int32, height int32) {
}

func (WlShellSurfaceStub) HandleWlShellSurfacePopupDone(ctx context.Context) {}

func unmarshalEventWlShellSurface(o *raw.Object, op uint16, args []byte, fds []int) (raw.HandleEventFunc, error) {
	switch op {
	case 0:
		var (
			serial uint32
			err    error
		)

		conn := o.Conn()
		if serial, args, err = conn.UnmarshalUint(args); err != nil {
			return nil, err
		}
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlShellSurfaceData).HandleWlShellSurfacePing(ctx,
					serial,
				)
			} else {
			}
		}, nil
	case 1:
		var (
			edges  uint32
			width  int32
			height int32
			err    error
		)

		conn := o.Conn()
		if edges, args, err = conn.UnmarshalUint(args); err != nil {
			return nil, err
		}
		if width, args, err = conn.UnmarshalInt(args); err != nil {
			return nil, err
		}
		if height, args, err = conn.UnmarshalInt(args); err != nil {
			return nil, err
		}
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlShellSurfaceData).HandleWlShellSurfaceConfigure(ctx,
					edges, width, height,
				)
			} else {
			}
		}, nil
	case 2:
		var (
			err error
		)

		conn := o.Conn()
		if err = conn.UnmarshalEnd(args); err != nil {
			return nil, err
		}

		return func(ctx context.Context) {
			if userData := o.UserData(); userData != nil {
				userData.(WlShellSurfaceData).HandleWlShellSurfacePopupDone(ctx)
			} else {
			}
		}, nil
	default:
		return nil, fmt.Errorf("wl_shell_surface: invalid event opcode %d", op)
	}
}

const WlShellSurfaceName = "wl_shell_surface"

var interfaceWlShellSurface = raw.Interface{
	Name:           "wl_shell_surface",
	Requests:       []string{"pong", "move", "resize", "set_toplevel", "set_transient", "set_fullscreen", "set_popup", "set_maximized", "set_title", "set_class"},
	Events:         []string{"ping", "configure", "popup_done"},
	EventsFDs:      []int{0, 0, 0},
	UnmarshalEvent: unmarshalEventWlShellSurface,
}

// These values are used to indicate which edge of a surface
// is being dragged in a resize operation. The server may
// use this information to adapt its behavior, e.g. choose
// an appropriate cursor image.
const (
	WlShellSurfaceResizeNone        = 0
	WlShellSurfaceResizeTop         = 1
	WlShellSurfaceResizeBottom      = 2
	WlShellSurfaceResizeLeft        = 4
	WlShellSurfaceResizeTopLeft     = 5
	WlShellSurfaceResizeBottomLeft  = 6
	WlShellSurfaceResizeRight       = 8
	WlShellSurfaceResizeTopRight    = 9
	WlShellSurfaceResizeBottomRight = 10
)

// These flags specify details of the expected behaviour
// of transient surfaces. Used in the set_transient request.
const (
	WlShellSurfaceTransientInactive = 0x1
)

// Hints to indicate to the compositor how to deal with a conflict
// between the dimensions of the surface and the dimensions of the
// output. The compositor is free to ignore this parameter.
const (
	WlShellSurfaceFullscreenMethodDefault = 0
	WlShellSurfaceFullscreenMethodScale   = 1
	WlShellSurfaceFullscreenMethodDriver  = 2
	WlShellSurfaceFullscreenMethodFill    = 3
)

// A surface is a rectangular area that may be displayed on zero
// or more outputs, and shown any number of times at the compositor's
// discretion. They can present wl_buffers, receive user input, and
// define a local coordinate system.
//
// The size of a surface (and relative positions on it) is described
// in surface-local coordinates, which may differ from the buffer
// coordinates of the pixel content, in case a buffer_transform
// or a buffer_scale is used.
//
// A surface without a "role" is fairly useless: a compositor does
// not know where, when or how to present it. The role is the
// purpose of a wl_surface. Examples of roles are a cursor for a
// pointer (as set by wl_pointer.set_cursor), a drag icon
// (wl_data_device.start_drag), a sub-surface
// (wl_subcompositor.get_subsurface), and a window as defined by a
// shell protocol (e.g. wl_shell.get_shell_surface).
//
// A surface can have only one role at a time. Initially a
// wl_surface does not have a role. Once a wl_surface is given a
// role, it is set permanently for the whole lifetime of the
// wl_surface object. Giving the current role again is allowed,
// unless explicitly forbidden by the relevant interface
// specification.
//
// Surface roles are given by requests in other interfaces such as
// wl_pointer.set_cursor. The request should explicitly mention
// that this request gives a role to a wl_surface. Often, this
// request also creates a new protocol object that represents the
// role and adds additional functionality to wl_surface. When a
// client wants to destroy a wl_surface, they must destroy this role
// object before the wl_surface, otherwise a defunct_role_object error is
// sent.
//
// Destroying the role object does not remove the role from the
// wl_surface, but it may stop the wl_surface from "playing the role".
// For instance, if a wl_subsurface object is destroyed, the wl_surface
// it was created for will be unmapped and forget its position and
// z-order. It is allowed to create a wl_subsurface for the same
// wl_surface again, but it is not allowed to use the wl_surface as
// a cursor (cursor is a different role than sub-surface, and role
// switching is not allowed).
type WlSurface struct {
	_   raw.Marker[WlSurface]
	raw *raw.Object
}

// Conn returns the underlying connection.
func (o WlSurface) Conn() *wlcl.Connection { return (*wlcl.Connection)(o.raw.Conn()) }

// IsSet returns true if the object is valid (non-zero).
func (o WlSurface) IsSet() bool { return o.raw != nil }

// Version returns the object's version.
func (o WlSurface) Version() uint32 { return o.raw.Version() }

// UserData returns the object's user data.
func (o WlSurface) UserData() WlSurfaceData { return o.raw.UserData().(WlSurfaceData) }

// SetUserData sets the object's user data.
func (o WlSurface) SetUserData(v WlSurfaceData) { o.raw.SetUserData(v) }

// Deletes the surface and invalidates its object ID.
func (o WlSurface) Destroy() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 0, func() (args []byte, fds []int) {
		o.raw.Destroy()
		return
	})
	return
}

// Set a buffer as the content of this surface.
//
// The new size of the surface is calculated based on the buffer
// size transformed by the inverse buffer_transform and the
// inverse buffer_scale. This means that at commit time the supplied
// buffer size must be an integer multiple of the buffer_scale. If
// that's not the case, an invalid_size error is sent.
//
// The x and y arguments specify the location of the new pending
// buffer's upper left corner, relative to the current buffer's upper
// left corner, in surface-local coordinates. In other words, the
// x and y, combined with the new surface size define in which
// directions the surface's size changes. Setting anything other than 0
// as x and y arguments is discouraged, and should instead be replaced
// with using the separate wl_surface.offset request.
//
// When the bound wl_surface version is 5 or higher, passing any
// non-zero x or y is a protocol violation, and will result in an
// 'invalid_offset' error being raised. The x and y arguments are ignored
// and do not change the pending state. To achieve equivalent semantics,
// use wl_surface.offset.
//
// Surface contents are double-buffered state, see wl_surface.commit.
//
// The initial surface contents are void; there is no content.
// wl_surface.attach assigns the given wl_buffer as the pending
// wl_buffer. wl_surface.commit makes the pending wl_buffer the new
// surface contents, and the size of the surface becomes the size
// calculated from the wl_buffer, as described above. After commit,
// there is no pending buffer until the next attach.
//
// Committing a pending wl_buffer allows the compositor to read the
// pixels in the wl_buffer. The compositor may access the pixels at
// any time after the wl_surface.commit request. When the compositor
// will not access the pixels anymore, it will send the
// wl_buffer.release event. Only after receiving wl_buffer.release,
// the client may reuse the wl_buffer. A wl_buffer that has been
// attached and then replaced by another attach instead of committed
// will not receive a release event, and is not used by the
// compositor.
//
// If a pending wl_buffer has been committed to more than one wl_surface,
// the delivery of wl_buffer.release events becomes undefined. A well
// behaved client should not rely on wl_buffer.release events in this
// case. Alternatively, a client could create multiple wl_buffer objects
// from the same backing storage or use a protocol extension providing
// per-commit release notifications.
//
// Destroying the wl_buffer after wl_buffer.release does not change
// the surface contents. Destroying the wl_buffer before wl_buffer.release
// is allowed as long as the underlying buffer storage isn't re-used (this
// can happen e.g. on client process termination). However, if the client
// destroys the wl_buffer before receiving the wl_buffer.release event and
// mutates the underlying buffer storage, the surface contents become
// undefined immediately.
//
// If wl_surface.attach is sent with a NULL wl_buffer, the
// following wl_surface.commit will remove the surface content.
//
// If a pending wl_buffer has been destroyed, the result is not specified.
// Many compositors are known to remove the surface content on the following
// wl_surface.commit, but this behaviour is not universal. Clients seeking to
// maximise compatibility should not destroy pending buffers and should
// ensure that they explicitly remove content from surfaces, even after
// destroying buffers.
func (o WlSurface) Attach(buffer WlBuffer, x int32, y int32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 1, func() (args []byte, fds []int) {
		args = make([]byte, 0, 12)
		args = conn.MarshalNullObject(args, buffer.raw)
		args = conn.MarshalInt(args, x)
		args = conn.MarshalInt(args, y)
		return
	})
	return
}

// This request is used to describe the regions where the pending
// buffer is different from the current surface contents, and where
// the surface therefore needs to be repainted. The compositor
// ignores the parts of the damage that fall outside of the surface.
//
// Damage is double-buffered state, see wl_surface.commit.
//
// The damage rectangle is specified in surface-local coordinates,
// where x and y specify the upper left corner of the damage rectangle.
//
// The initial value for pending damage is empty: no damage.
// wl_surface.damage adds pending damage: the new pending damage
// is the union of old pending damage and the given rectangle.
//
// wl_surface.commit assigns pending damage as the current damage,
// and clears pending damage. The server will clear the current
// damage as it repaints the surface.
//
// Note! New clients should not use this request. Instead damage can be
// posted with wl_surface.damage_buffer which uses buffer coordinates
// instead of surface coordinates.
func (o WlSurface) Damage(x int32, y int32, width int32, height int32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 2, func() (args []byte, fds []int) {
		args = make([]byte, 0, 16)
		args = conn.MarshalInt(args, x)
		args = conn.MarshalInt(args, y)
		args = conn.MarshalInt(args, width)
		args = conn.MarshalInt(args, height)
		return
	})
	return
}

// Request a notification when it is a good time to start drawing a new
// frame, by creating a frame callback. This is useful for throttling
// redrawing operations, and driving animations.
//
// When a client is animating on a wl_surface, it can use the 'frame'
// request to get notified when it is a good time to draw and commit the
// next frame of animation. If the client commits an update earlier than
// that, it is likely that some updates will not make it to the display,
// and the client is wasting resources by drawing too often.
//
// The frame request will take effect on the next wl_surface.commit.
// The notification will only be posted for one frame unless
// requested again. For a wl_surface, the notifications are posted in
// the order the frame requests were committed.
//
// The server must send the notifications so that a client
// will not send excessive updates, while still allowing
// the highest possible update rate for clients that wait for the reply
// before drawing again. The server should give some time for the client
// to draw and commit after sending the frame callback events to let it
// hit the next output refresh.
//
// A server should avoid signaling the frame callbacks if the
// surface is not visible in any way, e.g. the surface is off-screen,
// or completely obscured by other opaque surfaces.
//
// The object returned by this request will be destroyed by the
// compositor after the callback is fired and as such the client must not
// attempt to use it after that point.
//
// The callback_data passed in the callback is the current time, in
// milliseconds, with an undefined base.
func (o WlSurface) Frame() WlCallback {
	conn := o.raw.Conn()
	var callback *raw.Object
	conn.SendRequest(o.raw, 3, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		callback, args = conn.MarshalNewID(args, &interfaceWlCallback, o.raw.Version())
		return
	})
	return As[WlCallback](callback)
}

// This request sets the region of the surface that contains
// opaque content.
//
// The opaque region is an optimization hint for the compositor
// that lets it optimize the redrawing of content behind opaque
// regions.  Setting an opaque region is not required for correct
// behaviour, but marking transparent content as opaque will result
// in repaint artifacts.
//
// The opaque region is specified in surface-local coordinates.
//
// The compositor ignores the parts of the opaque region that fall
// outside of the surface.
//
// Opaque region is double-buffered state, see wl_surface.commit.
//
// wl_surface.set_opaque_region changes the pending opaque region.
// wl_surface.commit copies the pending region to the current region.
// Otherwise, the pending and current regions are never changed.
//
// The initial value for an opaque region is empty. Setting the pending
// opaque region has copy semantics, and the wl_region object can be
// destroyed immediately. A NULL wl_region causes the pending opaque
// region to be set to empty.
func (o WlSurface) SetOpaqueRegion(region WlRegion) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 4, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalNullObject(args, region.raw)
		return
	})
	return
}

// This request sets the region of the surface that can receive
// pointer and touch events.
//
// Input events happening outside of this region will try the next
// surface in the server surface stack. The compositor ignores the
// parts of the input region that fall outside of the surface.
//
// The input region is specified in surface-local coordinates.
//
// Input region is double-buffered state, see wl_surface.commit.
//
// wl_surface.set_input_region changes the pending input region.
// wl_surface.commit copies the pending region to the current region.
// Otherwise the pending and current regions are never changed,
// except cursor and icon surfaces are special cases, see
// wl_pointer.set_cursor and wl_data_device.start_drag.
//
// The initial value for an input region is infinite. That means the
// whole surface will accept input. Setting the pending input region
// has copy semantics, and the wl_region object can be destroyed
// immediately. A NULL wl_region causes the input region to be set
// to infinite.
func (o WlSurface) SetInputRegion(region WlRegion) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 5, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalNullObject(args, region.raw)
		return
	})
	return
}

// Surface state (input, opaque, and damage regions, attached buffers,
// etc.) is double-buffered. Protocol requests modify the pending state,
// as opposed to the active state in use by the compositor.
//
// A commit request atomically creates a content update from the pending
// state, even if the pending state has not been touched. The content
// update is placed in a queue until it becomes active. After commit, the
// new pending state is as documented for each related request.
//
// When the content update is applied, the wl_buffer is applied before all
// other state. This means that all coordinates in double-buffered state
// are relative to the newly attached wl_buffers, except for
// wl_surface.attach itself. If there is no newly attached wl_buffer, the
// coordinates are relative to the previous content update.
//
// All requests that need a commit to become effective are documented
// to affect double-buffered state.
//
// Other interfaces may add further double-buffered surface state.
func (o WlSurface) Commit() {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 6, func() (args []byte, fds []int) {
		return
	})
	return
}

// This request sets the transformation that the client has already applied
// to the content of the buffer. The accepted values for the transform
// parameter are the values for wl_output.transform.
//
// The compositor applies the inverse of this transformation whenever it
// uses the buffer contents.
//
// Buffer transform is double-buffered state, see wl_surface.commit.
//
// A newly created surface has its buffer transformation set to normal.
//
// wl_surface.set_buffer_transform changes the pending buffer
// transformation. wl_surface.commit copies the pending buffer
// transformation to the current one. Otherwise, the pending and current
// values are never changed.
//
// The purpose of this request is to allow clients to render content
// according to the output transform, thus permitting the compositor to
// use certain optimizations even if the display is rotated. Using
// hardware overlays and scanning out a client buffer for fullscreen
// surfaces are examples of such optimizations. Those optimizations are
// highly dependent on the compositor implementation, so the use of this
// request should be considered on a case-by-case basis.
//
// Note that if the transform value includes 90 or 270 degree rotation,
// the width of the buffer will become the surface height and the height
// of the buffer will become the surface width.
//
// If transform is not one of the values from the
// wl_output.transform enum the invalid_transform protocol error
// is raised.
func (o WlSurface) SetBufferTransform(transform int32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 7, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalInt(args, transform)
		return
	})
	return
}

// This request sets an optional scaling factor on how the compositor
// interprets the contents of the buffer attached to the window.
//
// Buffer scale is double-buffered state, see wl_surface.commit.
//
// A newly created surface has its buffer scale set to 1.
//
// wl_surface.set_buffer_scale changes the pending buffer scale.
// wl_surface.commit copies the pending buffer scale to the current one.
// Otherwise, the pending and current values are never changed.
//
// The purpose of this request is to allow clients to supply higher
// resolution buffer data for use on high resolution outputs. It is
// intended that you pick the same buffer scale as the scale of the
// output that the surface is displayed on. This means the compositor
// can avoid scaling when rendering the surface on that output.
//
// Note that if the scale is larger than 1, then you have to attach
// a buffer that is larger (by a factor of scale in each dimension)
// than the desired surface size.
//
// If scale is not greater than 0 the invalid_scale protocol error is
// raised.
func (o WlSurface) SetBufferScale(scale int32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 8, func() (args []byte, fds []int) {
		args = make([]byte, 0, 4)
		args = conn.MarshalInt(args, scale)
		return
	})
	return
}

// This request is used to describe the regions where the pending
// buffer is different from the current surface contents, and where
// the surface therefore needs to be repainted. The compositor
// ignores the parts of the damage that fall outside of the surface.
//
// Damage is double-buffered state, see wl_surface.commit.
//
// The damage rectangle is specified in buffer coordinates,
// where x and y specify the upper left corner of the damage rectangle.
//
// The initial value for pending damage is empty: no damage.
// wl_surface.damage_buffer adds pending damage: the new pending
// damage is the union of old pending damage and the given rectangle.
//
// wl_surface.commit assigns pending damage as the current damage,
// and clears pending damage. The server will clear the current
// damage as it repaints the surface.
//
// This request differs from wl_surface.damage in only one way - it
// takes damage in buffer coordinates instead of surface-local
// coordinates. While this generally is more intuitive than surface
// coordinates, it is especially desirable when using wp_viewport
// or when a drawing library (like EGL) is unaware of buffer scale
// and buffer transform.
//
// Note: Because buffer transformation changes and damage requests may
// be interleaved in the protocol stream, it is impossible to determine
// the actual mapping between surface and buffer damage until
// wl_surface.commit time. Therefore, compositors wishing to take both
// kinds of damage into account will have to accumulate damage from the
// two requests separately and only transform from one to the other
// after receiving the wl_surface.commit.
func (o WlSurface) DamageBuffer(x int32, y int32, width int32, height int32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 9, func() (args []byte, fds []int) {
		args = make([]byte, 0, 16)
		args = conn.MarshalInt(args, x)
		args = conn.MarshalInt(args, y)
		args = conn.MarshalInt(args, width)
		args = conn.MarshalInt(args, height)
		return
	})
	return
}

// The x and y arguments specify the location of the new pending
// buffer's upper left corner, relative to the current buffer's upper
// left corner, in surface-local coordinates. In other words, the
// x and y, combined with the new surface size define in which
// directions the surface's size changes.
//
// The exact semantics of wl_surface.offset are role-specific. Refer to
// the documentation of specific roles for more information.
//
// Surface location offset is double-buffered state, see
// wl_surface.commit.
//
// This request is semantically equivalent to and the replaces the x and y
// arguments in the wl_surface.attach request in wl_surface versions prior
// to 5. See wl_surface.attach for details.
func (o WlSurface) Offset(x int32, y int32) {
	conn := o.raw.Conn()
	conn.SendRequest(o.raw, 10, func() (args []byte, fds []int) {
		args = make([]byte, 0, 8)
		args = conn.MarshalInt(args, x)
		args = conn.MarshalInt(args, y)
		return
	})
	return
}

type WlSurfaceData interface {
	// This is emitted whenever a surface's creation, movement, or resizing
	// results in some part of it being within the scanout region of an
	// output.
	//
	// Note that a surface may be overlapping with zero or more outputs.
	HandleWlSurfaceEnter(ctx context.Context, output WlOutput)

	// This is emitted whenever a surface's creation, movement, or resizing
	// results in it no longer having any part of it within the scanout region
	// of an output.
	//
	// Clients should not use the number of outputs the surface is on for frame
	// throttling purposes. The surface might be hidden even if no leave event
	// has been sent, and the compositor might expect new surface content
	// updates even if no enter event has been sent. The frame event should be
	// used instead.
	HandleWlSurfaceLeave(ctx context.Context, output WlOutput)

	// This event indicates the preferred buffer scale for this surface. It is
	// sent whenever the compositor's preference changes.
	//
	// Before receiving this event the preferred buffer scale for this surface
	// is 1.
	//
	// It is intended that scaling aware clients use this event to scale their
	// content and use wl_surface.set_buffer_scale to indicate the scale they
	// have rendered with. This allows clients to supply a higher detail
	// buffer.
	//
	// The compositor shall emit a scale value greater than 0.
	HandleWlSurfacePreferredBufferScale(ctx context.Context, factor int32)

	// This event indicates the preferred buffer transform for this surface.
	// It is sent whenever the compositor's preference changes.
	//
	// Before receiving this event the preferred buffer transform for this
	// surface is normal.
	//
	// Applying this transformation to the surface buffer contents and using
	// wl_surface.set_buffer_transform might allow the compositor to use the
	// surface buffer more efficiently.
	HandleWlSurfacePreferredBufferTransform(ctx context.Context, transform uint32)
}

