// The wl_pointer interface represents one or more input devices,
// such as mice, which control the pointer location and pointer_focus
// of a seat.
//
// The wl_pointer interface generates motion, enter and leave
// events for the surfaces that the pointer is located over,
// and button and axis events for button presses, button releases
// and scrolling.
type WlPointer struct {
	_   raw.Marker[WlPointer]
	raw *raw.Object
}

// Conn returns the underlying connection.
func (o WlPointer) Conn() *wlcl.Connection { return (*wlcl.Connection)(o.raw.Conn()) }

// IsSet returns true if the object is valid (non-zero).
func (o WlPointer) IsSet() bool { return o.raw != nil }

// Version returns the object's version.
